const files = fs.readdirSync(dir).filter(f => f.endsWith('.txt'));
const results = {};
for (let i = 0; i < files.length; i += 5) {
  const batch = files.slice(i, i+5);
  const summaries = await Promise.all(batch.map(async f => {
    const text = fs.readFileSync(path.join(dir, f), 'utf8');
    const msg = await client.messages.create({ model: 'claude-haiku-4-5-20251001', max_tokens: 100,
      messages: [{ role: 'user', content: `Summarize in 2 sentences: ${text}` }] });
    return [f, msg.content[0].text];
  }));
  summaries.forEach(([f, s]) => results[f] = s);
}
fs.writeFileSync('summaries.json', JSON.stringify(results, null, 2));
